section_text:
[gcode_macro G29]
variable_k: 1
gcode:
    {% set temp = printer["heater_generic chamber"].target %}
      M141 S0
    {% if temp > 0 %}
      G4 P15000
    {% endif %}

    {% if k|int==1 %}
        BED_MESH_CLEAR                                                                                           ; Clear levelling data
        BED_MESH_CALIBRATE ADAPTIVE=1 ADAPTIVE_MARGIN=5                                                          ; Start adaptive meshing
    {% endif %}   
    M141 S{temp}
